import React, { useEffect, useState } from "react";
import Modal from "./components/Modal";
import AssetForm from "./components/AssetForm";
import IncidentForm from "./components/IncidentForm";
import TenantForm from "./components/TenantForm";
import "./styles.css";

const TENANT_API = process.env.REACT_APP_TENANT_API;
const ASSET_API = process.env.REACT_APP_ASSET_API;
const INCIDENT_API = process.env.REACT_APP_INCIDENT_API;

function App() {
  const [tenants, setTenants] = useState([]);
  const [selectedTenant, setSelectedTenant] = useState("");

  const [assets, setAssets] = useState([]);
  const [incidents, setIncidents] = useState([]);

  const [modal, setModal] = useState(null);
  const [editData, setEditData] = useState(null);

  useEffect(() => {
    fetchTenants();
  }, []);

  useEffect(() => {
    if (selectedTenant) loadData();
  }, [selectedTenant]);

  const fetchTenants = async () => {
    const res = await fetch(TENANT_API);
    const data = await res.json();
    setTenants(data);
    if (data.length > 0) setSelectedTenant(data[0].tenantId);
  };

  const loadData = async () => {
    const headers = { "X-Tenant-ID": selectedTenant };

    const assets = await fetch(ASSET_API, { headers }).then(r => r.json());
    const incidents = await fetch(INCIDENT_API, { headers }).then(r => r.json());

    setAssets(assets);
    setIncidents(incidents);
  };

  return (
    <div className="container">

      <h2>Multi-Tenant ITOM</h2>

      <select onChange={(e) => setSelectedTenant(e.target.value)}>
        {tenants.map(t => <option key={t.tenantId} value={t.tenantId}>{t.name}</option>)}
      </select>

      <button onClick={() => setModal("tenant")}>+ Tenant</button>
      <button onClick={() => setModal("asset")}>+ Asset</button>
      <button onClick={() => setModal("incident")}>+ Incident</button>

      <div className="card">
        <h3>Assets</h3>
        {assets.map(a => (
          <div key={a.id}>
            {a.name} ({a.type})
          </div>
        ))}
      </div>

      <div className="card">
        <h3>Incidents</h3>
        {incidents.map(i => (
          <div key={i.id}>
            {i.title} - {i.severity}
          </div>
        ))}
      </div>

      <Modal isOpen={modal === "asset"} onClose={() => setModal(null)} title="Asset">
        <AssetForm onSubmit={async (data) => {
          await fetch(ASSET_API, {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
              "X-Tenant-ID": selectedTenant
            },
            body: JSON.stringify(data)
          });
          setModal(null);
          loadData();
        }} />
      </Modal>

      <Modal isOpen={modal === "incident"} onClose={() => setModal(null)} title="Incident">
        <IncidentForm assets={assets} onSubmit={async (data) => {
          await fetch(INCIDENT_API, {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
              "X-Tenant-ID": selectedTenant
            },
            body: JSON.stringify(data)
          });
          setModal(null);
          loadData();
        }} />
      </Modal>

      <Modal isOpen={modal === "tenant"} onClose={() => setModal(null)} title="Tenant">
        <TenantForm onSubmit={async (data) => {
          await fetch(TENANT_API, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(data)
          });
          setModal(null);
          fetchTenants();
        }} />
      </Modal>

    </div>
  );
}

export default App;
